#include<bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=1e3+5,inf=INT_MAX;
int a[maxn][maxn],n,m;
int f[maxn][maxn][2];
int dfs(int x,int y,int from) {
	if(x<1||x>n||y<1||y>m) return -inf;
	if(f[x][y][from]!=-inf) return f[x][y][from];
	if(from==0) {
		f[x][y][from]=max({dfs(x+1,y,0),dfs(x,y-1,0),dfs(x,y-1,1)})+a[x][y];
	} else {
		f[x][y][from]=max(dfs(x-1,y,1),max(dfs(x,y-1,0),dfs(x,y-1,1)))+a[x][y];
	}
	return f[x][y][from];
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1; i<=n; i++)
		for(int j=1; j<=m; j++)
			cin>>a[i][j],f[i][j][0]=f[i][j][1]=-inf;
	f[1][1][0]=f[1][1][1]=a[1][1];
	cout<<dfs(n,m,1);
	return 0;
}
